		LABELITEM 'core_balance'
		PROJECTION
			'proj=longlat'
			'datum=WGS84'
			'no_defs'
		END
		CLASS
		NAME 'CoreRef' 
			STYLE
				SYMBOL "icons/coreref.png" 
				SIZE 4
				OUTLINECOLOR 255 0 0
				COLOR 214 205 104
			END
			LABEL 
				COLOR  255 0 0  		
				FONT "arial"
				TYPE truetype
				SIZE 8
				POSITION AUTO
				PARTIALS FALSE
			END
		END
	END
