			NAME 'Surveyed Building' 	
			EXPRESSION ('[building_status]' = 'Surveyed')			
			STYLE
				SYMBOL "icons/building_yellow.png" 
				SIZE 18			
			END	  
		END
		CLASS
			NAME 'Resurveyed Building' 	
			EXPRESSION ('[building_status]' = 'Resurveyed')			
			STYLE
				SYMBOL "icons/building_red.png" 
				SIZE 18			
			END	  
		END
	END	
	
	
# ============== BUILDING (APPROVED POLYGON)============================================================ 	
	LAYER
		NAME 'BLDP'
		TYPE POLYGON
		DUMP true
		TEMPLATE fooOnlyForWMSGetFeatureInfo		
		INCLUDE "datashare.inc"
		DATA 'sp_geometry FROM vw_att_details_building_map USING UNIQUE system_id USING srid=4326'	
		#FILTER (%provinceFilter% AND (%layerFilter% ) AND (%bldRFSFilter% ))
		
		#VALIDATION		
			#'provinceFilter'   '.*'	
            #'layerFilter'   '.*'	
			#'bldRFSFilter'   '.*'	
		#END  
		METADATA
			'ows_title' 'Building'
		END
		STATUS OFF
		GROUP 'Network'
		TRANSPARENCY 30	
		CLASS
			NAME 'Approved Building' 			
			#EXPRESSION ('[building_status]' = 'Approved')
			STYLE
				 WIDTH 1 
			 OUTLINECOLOR 00 255 00
			 COLOR 255 0 0	
			END			
		END		
	END
	
# ===================BUILDING (APPROVED CENTROID POINT)======================================================= 
	LAYER
		NAME 'BLDC'
